import{_ as a,o,c as n,a3 as t}from"./chunks/framework.CjquFG0V.js";const h=JSON.parse('{"title":"218. Professional Development Leave Royal Children S","description":"","frontmatter":{"title":"218. Professional Development Leave Royal Children S","eba":"Mental Health Services 2024-2028","topics":["leave","education-pd"]},"headers":[],"relativePath":"ebas/mental-health/management-admin/education-pd/218-professional-development-leave-royal-children-s.md","filePath":"ebas/mental-health/management-admin/education-pd/218-professional-development-leave-royal-children-s.md"}'),l={name:"ebas/mental-health/management-admin/education-pd/218-professional-development-leave-royal-children-s.md"};function s(r,e,i,p,d,m){return o(),n("div",null,[...e[0]||(e[0]=[t('<h1 id="_218-professional-development-leave-royal-children-s" tabindex="-1">218. Professional Development Leave Royal Children S <a class="header-anchor" href="#_218-professional-development-leave-royal-children-s" aria-label="Permalink to &quot;218. Professional Development Leave Royal Children S&quot;">​</a></h1><p>Hospital</p><p><strong>218.1</strong> This clause only applies to Management and Administrative Officers at Royal Children’s Hospital classified under Part 2 of <a href="/eba/ebas/mental-health/schedules/07-management-and-administrative-officers-classifications.html">Schedule 7</a> of this Agreement.</p><p><strong>218.2</strong> In recognition of the importance of ongoing professional development, an Employee may seek approval for 5 days paid professional leave, to attend a conference, seminar, workshop etc approved by the Employer.</p><p><strong>218.3</strong> Professional development leave is non-cumulative.</p><p><strong>218.4</strong> The Employer shall not unreasonably withhold authorisation for Professional Development leave.</p><p><strong>218.5</strong> Professional development leave must be clearly linked to the Employee’s profession and may include a requirement to report back to other staff.</p>',7)])])}const f=a(l,[["render",s]]);export{h as __pageData,f as default};
